const item = $input.first().json;
const owner = item.owner_data || {};
const operators = owner.operators || [];
const body = item.body.callback_query;

const globalCredits = owner.credits_balance || 0;
const BOT_NAME = "TrinAi_Team_bot";

let teamList = "";
let buttons = [];

if (operators.length > 0) {
    operators.forEach((op, idx) => {
        const isOwner = op.Role === 'Owner' || op.isOwner === true;

        // Attivo: ha un Chat ID registrato
        const isActive = op.OperatorChatID && op.OperatorChatID !== null;

        // Pendente: non è attivo, ma l'invito è stato generato (la chiave ha un valore non vuoto)
        const isPending = !isActive && op.invitation_code && op.invitation_code.trim() !== "";

        // Bozza: creato in WebApp ma non ha ancora ricevuto la generazione dell'invito
        const isDraft = !isActive && !isPending;

        const opFirstName = op.OperatorName.split(' ')[0];

        if (isOwner) {
            const roleIcon = '👑';
            teamList += `${roleIcon} <b>${op.OperatorName}</b>\n`;
            teamList += `└ ${op.Role || "Owner"} | 💰 <b>${globalCredits} cred.</b> | ID: <code>${op.OperatorChatID}</code>\n\n`;
        } else if (isActive) {
            const roleIcon = '👤';
            const roleLabel = op.Job || op.Role || "Operatore";
            teamList += `${roleIcon} <b>${op.OperatorName}</b>\n`;
            teamList += `└ ${roleLabel} | ID: <code>${op.OperatorChatID}</code>\n\n`;

            // PULSANTI RIGA ATTIVO: Gestione e Rimozione
            buttons.push([
                { text: `⚙️ Gestisci ${opFirstName}`, callback_data: `m_team_info_${op.OperatorChatID}` },
                { text: `🗑️ Rimuovi`, callback_data: `m_team_del_${op.OperatorChatID}` }
            ]);
        } else if (isPending) {
            const roleIcon = '⏳';
            const roleLabel = op.Job || op.Role || "Operatore";
            const inviteLink = `https://t.me/${BOT_NAME}?start=${op.invitation_code}`;
            teamList += `${roleIcon} <b>${op.OperatorName}</b>\n`;
            teamList += `└ ${roleLabel} | ✉️ Link: <code>${inviteLink}</code>\n\n`;

            // PULSANTI RIGA PENDENTE: Condivisione nativa e Annullamento dell'invito
            const shareText = encodeURIComponent(`Unisciti al team di ${owner.ragione_sociale} su SiteBoS!`);
            const shareUrl = `https://t.me/share/url?url=${encodeURIComponent(inviteLink)}&text=${shareText}`;

            buttons.push([
                { text: `✉️ Condividi ${opFirstName}`, url: shareUrl },
                { text: `🗑️ Annulla`, callback_data: `m_team_cancel_${idx}` }
            ]);
        } else if (isDraft) {
            const roleIcon = '📝';
            const roleLabel = op.Job || op.Role || "Operatore";
            teamList += `${roleIcon} <b>${op.OperatorName}</b>\n`;
            teamList += `└ ${roleLabel} | ⚠️ <i>In attesa di invito</i>\n\n`;

            // PULSANTI RIGA BOZZA: Solo Generazione invito (acquisto dello slot)
            buttons.push([
                { text: `📩 Invita ${opFirstName} (20 Cr.)`, callback_data: `m_team_invite_${idx}` }
            ]);
        }
    });
}

// AZIONI GLOBALI (Sempre in fondo alla pulsantiera)
buttons.push([{ text: "📩 Genera Nuovo Invito Generico (20 Crediti)", callback_data: "m_team_add" }]);
buttons.push([{ text: "⬅️ Menu Principale", callback_data: "open_agent_control_center" }]);

// Rimosso ogni margine e allineate le righe a sinistra per una formattazione perfetta
const msgText = `👥 <b>GESTIONE TEAM: ${owner.ragione_sociale}</b>
━━━━━━━━━━━━━━━━━━━━
In questa sezione autorizzi i collaboratori ad operare con il tuo saldo aziendale.

${teamList}━━━━━━━━━━━━━━━━━━━━
💡 <i>Usa i tasti corrispondenti per invitare i membri in bozza, condividere i link attivi o gestire lo staff.</i>`;

return [{
    json: {
        ...item,
        telegramApiPayload: {
            method: "editMessageText",
            chat_id: body.message.chat.id,
            message_id: body.message.message_id,
            text: msgText,
            parse_mode: "HTML",
            reply_markup: { inline_keyboard: buttons }
        }
    }
}];

const item = $input.first().json;
const owner = item.owner_data || {};
const body = item.body.callback_query;

const chatId = body.message.chat.id;
const messageId = body.message.message_id;

const COSTO = 20;
const saldo = owner.credits_balance || 0;

let msgText = "";
let buttons = [];

if (saldo >= COSTO) {
    // --- CASO A: CREDITI SUFFICIENTI -> CHIEDI CONFERMA ---
    msgText = `
💳 <b>CONFERMA ACQUISTO SLOT</b>
━━━━━━━━━━━━━━━━━━━━
L'aggiunta di un nuovo collaboratore richiede l'attivazione di uno slot operatore.

💰 <b>Costo operazione:</b> ${COSTO} Crediti
📊 <b>Tuo saldo attuale:</b> ${saldo} Crediti
📉 <b>Saldo post-acquisto:</b> ${saldo - COSTO} Crediti

<i>I crediti scalati non sono rimborsabili dopo la generazione del link.</i>
━━━━━━━━━━━━━━━━━━━━
⚠️ <b>Vuoi procedere con l'acquisto?</b>`;

    buttons = [
        [{ text: `✅ Sì, conferma e scala ${COSTO} Crediti`, callback_data: "m_team_add_commit" }],
        [{ text: "❌ Annulla", callback_data: "m_team" }]
    ];

} else {
    // --- CASO B: CREDITI INSUFFICIENTI -> REINDIRIZZA A DASHBOARD ---
    msgText = `
⚠️ <b>CREDITI INSUFFICIENTI</b>
━━━━━━━━━━━━━━━━━━━━
Il tuo saldo attuale (<b>${saldo} Cr.</b>) non è sufficiente per generare un nuovo invito.

💰 <b>Costo richiesto:</b> ${COSTO} Crediti

Per autorizzare nuovi collaboratori nel tuo team, è necessario ricaricare il tuo "serbatoio di energia" sulla piattaforma ufficiale.`;

    buttons = [
        [{ text: "🔋 Ricarica Crediti Ora", url: "https://dashboard.trinai.it/" }],
        [{ text: "⬅️ Torna alla Lista Team", callback_data: "m_team" }]
    ];
}

return [{
    json: {
        ...item,
        telegramApiPayload: {
            method: "editMessageText",
            chat_id: chatId,
            message_id: messageId,
            text: msgText,
            parse_mode: "HTML",
            reply_markup: { inline_keyboard: buttons }
        }
    }
}];

const item = $input.first().json;

const owner = item.owner_data;
const body = item.body.callback_query;
const COSTO = 20;
const timestamp = new Date().toISOString();

const previousBalance = owner.credits_balance || 0;
const finalBalance = previousBalance - COSTO;

// 1. Aggiornamento owner_data (Persistence)
owner.credits_balance = finalBalance;
owner.last_update = timestamp;

// 2. Generazione Codice e Link (TrinAi_Team_bot)
const randomPart = Math.random().toString(36).substring(2, 7).toUpperCase();
const invCode = `INV-${owner.vat_number}-${randomPart}`;
const inviteLink = `https://t.me/TrinAi_Team_bot?start=${invCode}`;

// 3. Iniezione nuovo operatore nell'array (SENZA operator_credit)
const newOp = {
    OperatorName: `Collaboratore_${randomPart}`,
    invitation_code: invCode,
    OperatorChatID: null, 
    Role: "Operator",
    FreeHandOperator: true,
    status: "PENDING",
    created_at: timestamp
};

if (!owner.operators) owner.operators = [];
owner.operators.push(newOp);

// 4. TRANSACTION SUMMARY
const transaction_summary = {
    model: "operator_invite_logic_v1",
    is_long_context: false,
    usage: { in: 0, out: 0 },
    usd_cost: 0,
    credits_deducted: COSTO,
    previous_balance: previousBalance,
    final_balance: finalBalance,
    timestamp: timestamp,
    billing_source: {
        use: "operator_invitation",
        wh: "https://prod.workflow.trinai.it/webhook/ef4aece4-9ec0-4026-a7a7-328562bcbdf6"
    }
};

// 5. Output
return [{
    json: {
        ...item,
        owner_data: owner,
        transaction_summary: transaction_summary,
        telegramApiPayload: {
            method: "editMessageText",
            chat_id: body.message.chat.id,
            message_id: body.message.message_id,
            text: `
✅ <b>ACQUISTO COMPLETATO!</b>
━━━━━━━━━━━━━━━━━━━━
Abbiamo scalato <b>${COSTO} crediti</b>.

Invia questo link al tuo collaboratore:
<code>${inviteLink}</code>

📍 <i>L'invito è ora visibile nella tua lista Team come 'Pendente'.</i>`,
            parse_mode: "HTML",
            reply_markup: {
                inline_keyboard: [[{ text: "⬅️ Torna alla Lista", callback_data: "m_team" }]]
            }
        }
    }
}];

const item = $input.first().json;
const owner = item.owner_data || {};
const body = item.body.callback_query;

const COSTO = 20;
const timestamp = new Date().toISOString();

// 1. Estrazione dell'indice dell'operatore dal callback (es: m_team_invite_1 -> 1)
const opIndex = parseInt(body.data.split('_').pop());
if (isNaN(opIndex) || !owner.operators || !owner.operators[opIndex]) {
    throw new Error("Errore: Impossibile trovare l'operatore all'indice specificato.");
}

const targetOp = owner.operators[opIndex];
const opFirstName = targetOp.OperatorName.split(' ')[0];

// 2. Controllo Saldo
const previousBalance = owner.credits_balance || 0;
if (previousBalance < COSTO) {
    throw new Error("Errore: Crediti insufficienti per avviare l'invito.");
}

// 3. Addebito Crediti (Persistence)
const finalBalance = previousBalance - COSTO;
owner.credits_balance = finalBalance;
owner.last_update = timestamp;

// 4. Generazione Codice e Link
const randomPart = Math.random().toString(36).substring(2, 7).toUpperCase();
const invCode = `INV-${owner.vat_number}-${randomPart}`;
const inviteLink = `https://t.me/TrinAi_Team_bot?start=${invCode}`;

// Aggiornamento anagrafica specifica dello studio
targetOp.invitation_code = invCode;
targetOp.status = "PENDING";
targetOp.created_at = timestamp;

// 5. Tracciato di Audit strutturato (billing_source)
const transaction_summary = {
    model: "operator_invite_logic_v1",
    is_long_context: false,
    usage: { in: 0, out: 0 },
    usd_cost: 0,
    credits_deducted: COSTO,
    previous_balance: previousBalance,
    final_balance: finalBalance,
    timestamp: timestamp,
    billing_source: {
        use: "operator_invitation",
        wh: "https://prod.workflow.trinai.it/webhook/ef4aece4-9ec0-4026-a7a7-328562bcbdf6"
    }
};

// 6. Ritorno
return [{
    json: {
        ...item,
        owner_data: owner,
        transaction_summary: transaction_summary,
        telegramApiPayload: {
            method: "editMessageText",
            chat_id: body.message.chat.id,
            message_id: body.message.message_id,
            text: `
✅ <b>INVITO GENERATO PER ${targetOp.OperatorName.toUpperCase()}!</b>
━━━━━━━━━━━━━━━━━━━━
Abbiamo scalato <b>${COSTO} crediti</b> per lo slot di ${opFirstName}.

Invia questo link al tuo collaboratore per completare l'onboarding:
<code>${inviteLink}</code>

📍 <i>Lo stato dell'operatore è ora aggiornato in 'Pendente' anche su WebApp.</i>`,
            parse_mode: "HTML",
            reply_markup: {
                inline_keyboard: [[{ text: "⬅️ Torna alla Lista", callback_data: "m_team" }]]
            }
        }
    }
}];

const item = $input.first().json;
const owner = item.owner_data || {};
const body = item.body.callback_query;

const timestamp = new Date().toISOString();

// 1. Estrazione dell'indice dell'operatore dal callback (es: m_team_cancel_1 -> 1)
const opIndex = parseInt(body.data.split('_').pop());
if (isNaN(opIndex) || !owner.operators || !owner.operators[opIndex]) {
    throw new Error("Errore: Impossibile trovare l'operatore all'indice specificato.");
}

const targetOp = owner.operators[opIndex];
const opFirstName = targetOp.OperatorName.split(' ')[0];

// 2. Revoca dell'invito (Reset allo stato bozza / Non rimborsabile)
targetOp.invitation_code = "";
targetOp.status = "";
targetOp.created_at = null; // Pulizia timestamp creazione invito

owner.last_update = timestamp;

// 3. Ritorno (Senza transaction_summary poiché non c'è variazione di saldo)
return [{
    json: {
        ...item,
        owner_data: owner,
        telegramApiPayload: {
            method: "editMessageText",
            chat_id: body.message.chat.id,
            message_id: body.message.message_id,
            text: `
❌ <b>INVITO ANNULLATO PER ${targetOp.OperatorName.toUpperCase()}</b>
━━━━━━━━━━━━━━━━━━━━
Il link di invito precedentemente generato per lo slot di ${opFirstName} è stato revocato con successo. Il vecchio link non è più attivo.

L'operatore è stato riportato in stato di 'Bozza' all'interno del tuo pannello di controllo.`,
            parse_mode: "HTML",
            reply_markup: {
                inline_keyboard: [[{ text: "⬅️ Torna alla Lista", callback_data: "m_team" }]]
            }
        }
    }
}];

